import os
import re
from flask import Flask, request, jsonify
import psycopg2
import psycopg2.extras

app = Flask(__name__)

# Database configuration from environment variables
DB_CONFIG = {
    'host': os.environ.get('DB_HOST', 'localhost'),
    'port': os.environ.get('DB_PORT', '5432'),
    'dbname': os.environ.get('DB_NAME', 'analytics'),
    'user': os.environ.get('DB_USER', 'postgres'),
    'password': os.environ.get('DB_PASSWORD', 'postgres'),
}

# Whitelist of allowed tables and columns for security
ALLOWED_TABLES = os.environ.get('ALLOWED_TABLES', '').split(',') if os.environ.get('ALLOWED_TABLES') else []
ALLOWED_OPERATORS = {'=', '!=', '>', '<', '>=', '<=', 'LIKE', 'ILIKE', 'IN', 'NOT IN', 'IS NULL', 'IS NOT NULL', 'BETWEEN'}
ALLOWED_AGGREGATES = {'COUNT', 'SUM', 'AVG', 'MIN', 'MAX'}
ALLOWED_ORDER_DIRECTIONS = {'ASC', 'DESC'}

MAX_LIMIT = 10000
DEFAULT_LIMIT = 100


def get_db_connection():
    """Create and return a database connection."""
    conn = psycopg2.connect(**DB_CONFIG)
    return conn


def validate_identifier(identifier):
    """Validate that an identifier (table/column name) is safe."""
    pattern = re.compile(r'^[a-zA-Z_][a-zA-Z0-9_.]*$')
    if not pattern.match(identifier):
        raise ValueError(f"Invalid identifier: {identifier}")
    return identifier


def get_table_columns(conn, schema, table):
    """Fetch actual column names from the database for validation."""
    query = """
        SELECT column_name 
        FROM information_schema.columns 
        WHERE table_schema = %s AND table_name = %s
    """
    with conn.cursor() as cur:
        cur.execute(query, (schema, table))
        return {row[0] for row in cur.fetchall()}


def get_available_tables(conn):
    """Fetch available tables from the database."""
    query = """
        SELECT table_schema, table_name 
        FROM information_schema.tables 
        WHERE table_schema NOT IN ('pg_catalog', 'information_schema')
        AND table_type = 'BASE TABLE'
    """
    with conn.cursor() as cur:
        cur.execute(query)
        return {f"{row[0]}.{row[1]}" for row in cur.fetchall()}


def validate_table(conn, table_name):
    """Validate table name against whitelist and database."""
    # Parse schema and table
    parts = table_name.split('.')
    if len(parts) == 2:
        schema, table = parts
    elif len(parts) == 1:
        schema, table = 'public', parts[0]
    else:
        raise ValueError(f"Invalid table name format: {table_name}")

    validate_identifier(schema)
    validate_identifier(table)

    full_name = f"{schema}.{table}"

    # Check whitelist if configured
    if ALLOWED_TABLES and full_name not in ALLOWED_TABLES and table not in ALLOWED_TABLES:
        raise ValueError(f"Table '{full_name}' is not in the allowed tables list")

    # Check table exists in database
    available = get_available_tables(conn)
    if full_name not in available:
        raise ValueError(f"Table '{full_name}' does not exist")

    return schema, table


def validate_columns(conn, schema, table, columns):
    """Validate column names against actual database columns."""
    actual_columns = get_table_columns(conn, schema, table)
    for col in columns:
        # Handle aggregate expressions like COUNT(column)
        clean_col = col
        for agg in ALLOWED_AGGREGATES:
            if col.upper().startswith(f"{agg}(") and col.endswith(')'):
                clean_col = col[len(agg)+1:-1]
                if clean_col == '*':
                    continue
                break

        if clean_col != '*' and clean_col not in actual_columns:
            raise ValueError(f"Column '{clean_col}' does not exist in table '{schema}.{table}'. Available columns: {sorted(actual_columns)}")


def build_select_clause(columns, schema, table, conn):
    """Build the SELECT clause with optional aggregations."""
    if not columns:
        return '*', []

    select_parts = []
    for col_spec in columns:
        if isinstance(col_spec, dict):
            # Handle aggregate: {"aggregate": "COUNT", "column": "id", "alias": "total"}
            agg = col_spec.get('aggregate', '').upper()
            col = col_spec.get('column', '*')
            alias = col_spec.get('alias', '')

            if agg and agg not in ALLOWED_AGGREGATES:
                raise ValueError(f"Invalid aggregate function: {agg}")

            if col != '*':
                validate_identifier(col)
                validate_columns(conn, schema, table, [col])

            if agg:
                part = f"{agg}({psycopg2.extensions.quote_ident(col, conn) if col != '*' else '*'})"
            else:
                part = psycopg2.extensions.quote_ident(col, conn)

            if alias:
                validate_identifier(alias)
                part += f" AS {psycopg2.extensions.quote_ident(alias, conn)}"

            select_parts.append(part)
        else:
            # Simple column name
            validate_identifier(col_spec)
            validate_columns(conn, schema, table, [col_spec])
            select_parts.append(psycopg2.extensions.quote_ident(col_spec, conn))

    return ', '.join(select_parts), []


def build_where_clause(filters, conn, schema, table):
    """Build WHERE clause from filter conditions."""
    if not filters:
        return '', []

    conditions = []
    params = []

    for f in filters:
        column = f.get('column')
        operator = f.get('operator', '=').upper()
        value = f.get('value')
        logic = f.get('logic', 'AND').upper()

        if logic not in ('AND', 'OR'):
            raise ValueError(f"Invalid logic operator: {logic}")

        if not column:
            raise ValueError("Filter must include 'column'")

        validate_identifier(column)
        validate_columns(conn, schema, table, [column])

        if operator not in ALLOWED_OPERATORS:
            raise ValueError(f"Invalid operator: {operator}. Allowed: {ALLOWED_OPERATORS}")

        col_quoted = psycopg2.extensions.quote_ident(column, conn)

        if operator in ('IS NULL', 'IS NOT NULL'):
            condition = f"{col_quoted} {operator}"
        elif operator == 'BETWEEN':
            if not isinstance(value, list) or len(value) != 2:
                raise ValueError("BETWEEN operator requires a list of exactly 2 values")
            condition = f"{col_quoted} BETWEEN %s AND %s"
            params.extend(value)
        elif operator in ('IN', 'NOT IN'):
            if not isinstance(value, list):
                raise ValueError(f"{operator} operator requires a list of values")
            placeholders = ', '.join(['%s'] * len(value))
            condition = f"{col_quoted} {operator} ({placeholders})"
            params.extend(value)
        else:
            condition = f"{col_quoted} {operator} %s"
            params.append(value)

        if conditions:
            conditions.append(f"{logic} {condition}")
        else:
            conditions.append(condition)

    where_clause = ' '.join(conditions)
    return f"WHERE {where_clause}", params


def build_group_by_clause(group_by, conn, schema, table):
    """Build GROUP BY clause."""
    if not group_by:
        return ''

    validated = []
    for col in group_by:
        validate_identifier(col)
        validate_columns(conn, schema, table, [col])
        validated.append(psycopg2.extensions.quote_ident(col, conn))

    return f"GROUP BY {', '.join(validated)}"


def build_having_clause(having_filters, conn):
    """Build HAVING clause for aggregate filters."""
    if not having_filters:
        return '', []

    conditions = []
    params = []

    for f in having_filters:
        aggregate = f.get('aggregate', '').upper()
        column = f.get('column', '*')
        operator = f.get('operator', '=').upper()
        value = f.get('value')

        if aggregate not in ALLOWED_AGGREGATES:
            raise ValueError(f"Invalid aggregate in HAVING: {aggregate}")

        if operator not in ALLOWED_OPERATORS:
            raise ValueError(f"Invalid operator in HAVING: {operator}")

        if column != '*':
            validate_identifier(column)
            col_quoted = psycopg2.extensions.quote_ident(column, conn)
        else:
            col_quoted = '*'

        condition = f"{aggregate}({col_quoted}) {operator} %s"
        conditions.append(condition)
        params.append(value)

    return f"HAVING {' AND '.join(conditions)}", params


def build_order_clause(order_by, conn, schema, table):
    """Build ORDER BY clause."""
    if not order_by:
        return ''

    order_parts = []
    for item in order_by:
        if isinstance(item, dict):
            col = item.get('column')
            direction = item.get('direction', 'ASC').upper()
            nulls = item.get('nulls', '').upper()  # FIRST or LAST
        else:
            col = item
            direction = 'ASC'
            nulls = ''

        validate_identifier(col)
        validate_columns(conn, schema, table, [col])

        if direction not in ALLOWED_ORDER_DIRECTIONS:
            raise ValueError(f"Invalid order direction: {direction}")

        part = f"{psycopg2.extensions.quote_ident(col, conn)} {direction}"

        if nulls in ('FIRST', 'LAST'):
            part += f" NULLS {nulls}"

        order_parts.append(part)

    return f"ORDER BY {', '.join(order_parts)}"


def build_join_clause(joins, conn):
    """Build JOIN clauses."""
    if not joins:
        return '', []

    join_parts = []
    for j in joins:
        join_type = j.get('type', 'INNER').upper()
        join_table = j.get('table')
        on_left = j.get('on_left')
        on_right = j.get('on_right')

        if join_type not in ('INNER', 'LEFT', 'RIGHT', 'FULL', 'CROSS', 'LEFT OUTER', 'RIGHT OUTER', 'FULL OUTER'):
            raise ValueError(f"Invalid join type: {join_type}")

        # Validate join table
        j_schema, j_table = validate_table(conn, join_table) if join_table else (None, None)

        validate_identifier(on_left)
        validate_identifier(on_right)

        j_table_quoted = f"{psycopg2.extensions.quote_ident(j_schema, conn)}.{psycopg2.extensions.quote_ident(j_table, conn)}"

        if join_type == 'CROSS':
            join_parts.append(f"CROSS JOIN {j_table_quoted}")
        else:
            join_parts.append(f"{join_type} JOIN {j_table_quoted} ON {on_left} = {on_right}")

    return ' '.join(join_parts), []


@app.route('/api/v1/query', methods=['POST'])
def dynamic_query():
    """
    Execute a dynamic query based on the request body.
    
    Expected JSON body:
    {
        "table": "schema.table_name" or "table_name",
        "columns": ["col1", "col2"] or [{"aggregate": "COUNT", "column": "id", "alias": "total"}],
        "filters": [
            {"column": "col1", "operator": "=", "value": "some_value", "logic": "AND"},
            {"column": "col2", "operator": ">", "value": 100}
        ],
        "joins": [
            {"type": "LEFT", "table": "other_table", "on_left": "t1.id", "on_right": "t2.t1_id"}
        ],
        "group_by": ["col1"],
        "having": [
            {"aggregate": "COUNT", "column": "id", "operator": ">", "value": 5}
        ],
        "order_by": [{"column": "col1", "direction": "DESC"}],
        "limit": 100,
        "offset": 0,
        "distinct": false
    }
    """
    try:
        data = request.get_json()
        if not data:
            return jsonify({'error': 'Request body must be JSON'}), 400

        table_name = data.get('table')
        if not table_name:
            return jsonify({'error': 'Table name is required'}), 400

        columns = data.get('columns', [])
        filters = data.get('filters', [])
        joins = data.get('joins', [])
        group_by = data.get('group_by', [])
        having = data.get('having', [])
        order_by = data.get('order_by', [])
        limit = min(int(data.get('limit', DEFAULT_LIMIT)), MAX_LIMIT)
        offset = int(data.get('offset', 0))
        distinct = data.get('distinct', False)

        conn = get_db_connection()
        try:
            # Validate table
            schema, table = validate_table(conn, table_name)
            table_quoted = f"{psycopg2.extensions.quote_ident(schema, conn)}.{psycopg2.extensions.quote_ident(table, conn)}"

            # Build query parts
            select_clause, select_params = build_select_clause(columns, schema, table, conn)
            join_clause, join_params = build_join_clause(joins, conn)
            where_clause, where_params = build_where_clause(filters, conn, schema, table)
            group_by_clause = build_group_by_clause(group_by, conn, schema, table)
            having_clause, having_params = build_having_clause(having, conn)
            order_clause = build_order_clause(order_by, conn, schema, table)

            distinct_keyword = "DISTINCT " if distinct else ""

            # Assemble query
            query = f"SELECT {distinct_keyword}{select_clause} FROM {table_quoted}"

            if join_clause:
                query += f" {join_clause}"
            if where_clause:
                query += f" {where_clause}"
            if group_by_clause:
                query += f" {group_by_clause}"
            if having_clause:
                query += f" {having_clause}"
            if order_clause:
                query += f" {order_clause}"

            query += f" LIMIT %s OFFSET %s"

            # Combine all params
            all_params = select_params + join_params + where_params + having_params + [limit, offset]

            # Execute query
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute(query, all_params)
                rows = cur.fetchall()

                # Get count query
                count_query = f"SELECT COUNT(*) as total FROM {table_quoted}"
                if join_clause:
                    count_query += f" {join_clause}"
                if where_clause:
                    count_query += f" {where_clause}"

                count_params = join_params + where_params
                cur.execute(count_query, count_params)
                total = cur.fetchone()['total']

            # Convert rows to serializable format
            results = []
            for row in rows:
                result = {}
                for key, value in row.items():
                    if hasattr(value, 'isoformat'):
                        result[key] = value.isoformat()
                    elif isinstance(value, memoryview):
                        result[key] = bytes(value).hex()
                    else:
                        result[key] = value
                results.append(result)

            return jsonify({
                'success': True,
                'data': results,
                'metadata': {
                    'total_count': total,
                    'returned_count': len(results),
                    'limit': limit,
                    'offset': offset,
                    'query': query  # For debugging; remove in production
                }
            })

        finally:
            conn.close()

    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except psycopg2.Error as e:
        return jsonify({'error': f'Database error: {str(e)}'}), 500
    except Exception as e:
        return jsonify({'error': f'Internal error: {str(e)}'}), 500


@app.route('/api/v1/tables', methods=['GET'])
def list_tables():
    """List all available tables."""
    try:
        conn = get_db_connection()
        try:
            available = get_available_tables(conn)

            # If whitelist is configured, filter
            if ALLOWED_TABLES:
                available = {t for t in available if t in ALLOWED_TABLES or t.split('.')[-1] in ALLOWED_TABLES}

            tables = sorted(available)
            return jsonify({
                'success': True,
                'tables': tables
            })
        finally:
            conn.close()
    except psycopg2.Error as e:
        return jsonify({'error': f'Database error: {str(e)}'}), 500


@app.route('/api/v1/tables/<path:table_name>/columns', methods=['GET'])
def list_columns(table_name):
    """List columns for a specific table."""
    try:
        conn = get_db_connection()
        try:
            schema, table = validate_table(conn, table_name)

            query = """
                SELECT column_name, data_type, is_nullable, column_default,
                       character_maximum_length, numeric_precision
                FROM information_schema.columns
                WHERE table_schema = %s AND table_name = %s
                ORDER BY ordinal_position
            """
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute(query, (schema, table))
                columns = cur.fetchall()

            return jsonify({
                'success': True,
                'table': f"{schema}.{table}",
                'columns': [dict(col) for col in columns]
            })
        finally:
            conn.close()
    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except psycopg2.Error as e:
        return jsonify({'error': f'Database error: {str(e)}'}), 500


@app.route('/api/v1/tables/<path:table_name>/distinct/<column_name>', methods=['GET'])
def distinct_values(table_name, column_name):
    """Get distinct values for a column (useful for filter dropdowns)."""
    try:
        conn = get_db_connection()
        try:
            schema, table = validate_table(conn, table_name)
            validate_identifier(column_name)
            validate_columns(conn, schema, table, [column_name])

            limit = min(int(request.args.get('limit', 100)), 1000)

            table_quoted = f"{psycopg2.extensions.quote_ident(schema, conn)}.{psycopg2.extensions.quote_ident(table, conn)}"
            col_quoted = psycopg2.extensions.quote_ident(column_name, conn)

            query = f"SELECT DISTINCT {col_quoted} FROM {table_quoted} WHERE {col_quoted} IS NOT NULL ORDER BY {col_quoted} LIMIT %s"

            with conn.cursor() as cur:
                cur.execute(query, (limit,))
                values = [row[0] for row in cur.fetchall()]

            # Serialize
            serialized = []
            for v in values:
                if hasattr(v, 'isoformat'):
                    serialized.append(v.isoformat())
                else:
                    serialized.append(v)

            return jsonify({
                'success': True,
                'column': column_name,
                'values': serialized
            })
        finally:
            conn.close()
    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except psycopg2.Error as e:
        return jsonify({'error': f'Database error: {str(e)}'}), 500


@app.route('/api/v1/aggregate', methods=['POST'])
def aggregate_query():
    """
    Execute an aggregate query.
    
    Expected JSON body:
    {
        "table": "schema.table_name",
        "aggregates": [
            {"function": "COUNT", "column": "*", "alias": "total"},
            {"function": "AVG", "column": "price", "alias": "avg_price"},
            {"function": "SUM", "column": "quantity", "alias": "total_qty"}
        ],
        "group_by": ["category", "region"],
        "filters": [...],
        "having": [...],
        "order_by": [{"column": "total", "direction": "DESC"}],
        "limit": 50
    }
    """
    try:
        data = request.get_json()
        if not data:
            return jsonify({'error': 'Request body must be JSON'}), 400

        table_name = data.get('table')
        if not table_name:
            return jsonify({'error': 'Table name is required'}), 400

        aggregates = data.get('aggregates', [])
        if not aggregates:
            return jsonify({'error': 'At least one aggregate is required'}), 400

        group_by = data.get('group_by', [])
        filters = data.get('filters', [])
        having = data.get('having', [])
        order_by = data.get('order_by', [])
        limit = min(int(data.get('limit', DEFAULT_LIMIT)), MAX_LIMIT)

        conn = get_db_connection()
        try:
            schema, table = validate_table(conn, table_name)
            table_quoted = f"{psycopg2.extensions.quote_ident(schema, conn)}.{psycopg2.extensions.quote_ident(table, conn)}"

            # Build select with aggregates
            select_parts = []

            # Add group by columns to select
            for col in group_by:
                validate_identifier(col)
                validate_columns(conn, schema, table, [col])
                select_parts.append(psycopg2.extensions.quote_ident(col, conn))

            # Add aggregate functions
            for agg in aggregates:
                func = agg.get('function', '').upper()
                col = agg.get('column', '*')
                alias = agg.get('alias', '')

                if func not in ALLOWED_AGGREGATES:
                    raise ValueError(f"Invalid aggregate function: {func}")

                if col != '*':
                    validate_identifier(col)
                    validate_columns(conn, schema, table, [col])
                    col_quoted = psycopg2.extensions.quote_ident(col, conn)
                else:
                    col_quoted = '*'

                part = f"{func}({col_quoted})"
                if alias:
                    validate_identifier(alias)
                    part += f" AS {psycopg2.extensions.quote_ident(alias, conn)}"
                select_parts.append(part)

            select_clause = ', '.join(select_parts)

            # Build other clauses
            where_clause, where_params = build_where_clause(filters, conn, schema, table)
            group_by_clause = build_group_by_clause(group_by, conn, schema, table)
            having_clause, having_params = build_having_clause(having, conn)

            # Build order by (allow ordering by aliases)
            order_clause = ''
            if order_by:
                order_parts = []
                for item in order_by:
                    if isinstance(item, dict):
                        col = item.get('column')
                        direction = item.get('direction', 'ASC').upper()
                    else:
                        col = item
                        direction = 'ASC'

                    validate_identifier(col)
                    if direction not in ALLOWED_ORDER_DIRECTIONS:
                        raise ValueError(f"Invalid order direction: {direction}")

                    order_parts.append(f"{psycopg2.extensions.quote_ident(col, conn)} {direction}")
                order_clause = f"ORDER BY {', '.join(order_parts)}"

            # Assemble query
            query = f"SELECT {select_clause} FROM {table_quoted}"
            if where_clause:
                query += f" {where_clause}"
            if group_by_clause:
                query += f" {group_by_clause}"
            if having_clause:
                query += f" {having_clause}"
            if order_clause:
                query += f" {order_clause}"
            query += f" LIMIT %s"

            all_params = where_params + having_params + [limit]

            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute(query, all_params)
                rows = cur.fetchall()

            results = []
            for row in rows:
                result = {}
                for key, value in row.items():
                    if hasattr(value, 'isoformat'):
                        result[key] = value.isoformat()
                    elif isinstance(value, memoryview):
                        result[key] = bytes(value).hex()
                    else:
                        result[key] = value
                results.append(result)

            return jsonify({
                'success': True,
                'data': results,
                'metadata': {
                    'returned_count': len(results),
                    'query': query
                }
            })

        finally:
            conn.close()

    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except psycopg2.Error as e:
        return jsonify({'error': f'Database error: {str(e)}'}), 500
    except Exception as e:
        return jsonify({'error': f'Internal error: {str(e)}'}), 500


